// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title BDLStaking — Block Label L-IDO onboarding / 540-day lock-up
 *
 * @notice Users stake the WebKey DAO 2.0 token (bdl, BSC 0xe0A281…, 9 dp)
 *         and lock it for 540 days to satisfy the Creator DAO participation
 *         condition ("Stake 1,000 BDL for 540 days"). This is the on-chain
 *         "lock-up contract" the BDL Token Issuance Plan requires to be deployed
 *         and CertiK-audited before TGE — the WebKey token is external, but the
 *         540-day lock is enforced here so stake amount + unlock date are read
 *         directly on-chain (the backend/DApp query {getStake} / {isEligible}).
 *
 * @dev Fee-on-transfer safe (measures received via balance diff). Each stake
 *      (re)sets the 540-day lock; the first stake fixes {start} and a global
 *      sequence number so the airdrop backend can bucket stakers into rounds
 *      (Early-Bird 1–1000, etc.) from the emitted cumulative total.
 *
 *      Eligibility for the airdrop = staked >= minStake (default 1,000 bdl).
 *      Unlock (withdrawal) is only permitted once 540 days have elapsed.
 */
contract BDLStaking is AccessControl, Pausable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    bytes32 public constant PAUSER_ROLE = keccak256("PAUSER_ROLE");

    IERC20 public immutable stakeToken; // bdl
    uint256 public immutable minStake; // e.g. 1000 * 10**9 (9 decimals)
    uint256 public immutable lockDuration; // 540 days in seconds

    struct StakeInfo {
        uint256 amount; // currently staked (raw units)
        uint64 start; // first-stake timestamp (round ordering)
        uint64 unlockTime; // start/last-stake + lockDuration
        uint32 sequence; // 1-based global stake order
    }

    mapping(address => StakeInfo) public stakes;
    address[] public stakers;
    uint256 public totalStaked;

    event Staked(
        address indexed user,
        uint256 amount,
        uint256 userTotal,
        uint256 cumulativeTotal,
        uint64 unlockTime,
        uint32 sequence
    );
    event Unstaked(address indexed user, uint256 amount);

    /**
     * @param stakeToken_   bdl token address (0xe0A281…dEaD on BSC mainnet).
     * @param minStake_     Minimum stake for eligibility, in token raw units
     *                      (1,000 bdl = 1000 * 10**9 at 9 decimals).
     * @param lockDuration_ Lock period in seconds (540 days = 46_656_000).
     * @param admin_        Admin / pauser (multisig in production).
     */
    constructor(
        address stakeToken_,
        uint256 minStake_,
        uint256 lockDuration_,
        address admin_
    ) {
        require(stakeToken_ != address(0) && admin_ != address(0), "zero addr");
        require(lockDuration_ > 0, "lock=0");
        stakeToken = IERC20(stakeToken_);
        minStake = minStake_;
        lockDuration = lockDuration_;
        _grantRole(DEFAULT_ADMIN_ROLE, admin_);
        _grantRole(PAUSER_ROLE, admin_);
    }

    /// @notice Stake bdl and (re)start the 540-day lock. Top-ups allowed.
    function stake(uint256 amount) external nonReentrant whenNotPaused {
        require(amount > 0, "amount=0");

        // Fee-on-transfer safe: credit only what actually arrived.
        uint256 before = stakeToken.balanceOf(address(this));
        stakeToken.safeTransferFrom(msg.sender, address(this), amount);
        uint256 received = stakeToken.balanceOf(address(this)) - before;
        require(received > 0, "no tokens received");

        StakeInfo storage s = stakes[msg.sender];
        if (s.sequence == 0) {
            stakers.push(msg.sender);
            s.sequence = uint32(stakers.length);
            s.start = uint64(block.timestamp);
        }
        s.amount += received;
        s.unlockTime = uint64(block.timestamp + lockDuration);
        totalStaked += received;

        emit Staked(msg.sender, received, s.amount, totalStaked, s.unlockTime, s.sequence);
    }

    /// @notice Withdraw the full stake once the 540-day lock has elapsed.
    function unstake() external nonReentrant {
        StakeInfo storage s = stakes[msg.sender];
        uint256 amount = s.amount;
        require(amount > 0, "nothing staked");
        require(block.timestamp >= s.unlockTime, "still locked");

        s.amount = 0;
        totalStaked -= amount;
        stakeToken.safeTransfer(msg.sender, amount);
        emit Unstaked(msg.sender, amount);
    }

    // ──────────────────────────────── Views ─────────────────────────────────

    function getStake(address user)
        external
        view
        returns (uint256 amount, uint64 start, uint64 unlockTime, uint32 sequence)
    {
        StakeInfo storage s = stakes[user];
        return (s.amount, s.start, s.unlockTime, s.sequence);
    }

    function stakedOf(address user) external view returns (uint256) {
        return stakes[user].amount;
    }

    function unlockTimeOf(address user) external view returns (uint64) {
        return stakes[user].unlockTime;
    }

    /// @notice True while the stake is within its 540-day lock.
    function isLocked(address user) external view returns (bool) {
        StakeInfo storage s = stakes[user];
        return s.amount > 0 && block.timestamp < s.unlockTime;
    }

    /// @notice Seconds remaining on the lock (0 if unlocked / not staked).
    function remainingLock(address user) external view returns (uint256) {
        StakeInfo storage s = stakes[user];
        if (s.amount == 0 || block.timestamp >= s.unlockTime) return 0;
        return s.unlockTime - block.timestamp;
    }

    /// @notice Meets the airdrop participation threshold (staked >= minStake).
    function isEligible(address user) external view returns (bool) {
        return stakes[user].amount >= minStake;
    }

    function stakerCount() external view returns (uint256) {
        return stakers.length;
    }

    // ──────────────────────────────── Admin ─────────────────────────────────

    function pause() external onlyRole(PAUSER_ROLE) {
        _pause();
    }

    function unpause() external onlyRole(PAUSER_ROLE) {
        _unpause();
    }
}

