// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";

/**
 * @title MockBDL — DEMO/TESTNET ONLY
 * @notice Stand-in for the real WebKey DAO 2.0 token (bdl, 9 decimals) so the
 *         staking flow can be demoed on a testnet where the real token doesn't
 *         exist. Freely mintable. DO NOT deploy to mainnet.
 */
contract MockBDL is ERC20 {
    constructor() ERC20("WebKey DAO 2.0 (Mock)", "bdl") {}

    function decimals() public pure override returns (uint8) {
        return 9;
    }

    /// @notice Anyone can mint themselves demo tokens.
    function mint(address to, uint256 amount) external {
        _mint(to, amount);
    }
}

